"use client"

import { ProfileCardUI, type ProfileCardUIProps } from "./profile-card-ui"
import {
  useProfileCard,
  type UseProfileCardOptions,
  type UseProfileCardReturn,
  type BapProfile,
} from "./use-profile-card"
import type { ReactNode } from "react"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export { ProfileCardUI, type ProfileCardUIProps } from "./profile-card-ui"
export {
  useProfileCard,
  type UseProfileCardOptions,
  type UseProfileCardReturn,
  type BapProfile,
} from "./use-profile-card"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ProfileCardProps {
  /** BAP ID to look up directly */
  bapId?: string
  /** Bitcoin address to resolve to a BAP identity */
  address?: string
  /** Base URL for the 1sat-stack API (default: https://api.1sat.app) */
  apiUrl?: string
  /** Optional CSS class name */
  className?: string
  /** Render prop for a follow button or other action in the header */
  renderAction?: (bapId: string) => ReactNode
  /** Callback to handle external links (e.g. open in system browser from a WebView) */
  onExternalLink?: (url: string) => void
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * Display a BAP identity profile card with avatar, name, bio,
 * identity key, and an optional action slot (e.g. follow button).
 *
 * Fetches profile data from the 1sat-stack BAP API. Provide either
 * a `bapId` for direct lookup or an `address` to resolve the identity.
 *
 * @example
 * ```tsx
 * import { ProfileCard } from "@/components/blocks/profile-card"
 *
 * <ProfileCard bapId="Go8vCHAa4S6AhXKdRp3nT9wJm" />
 *
 * <ProfileCard
 *   address="1A1zP1eP5QGefi2DMPTfTL5SLmv7DivfNa"
 *   renderAction={(bapId) => <FollowButton bapId={bapId} />}
 * />
 * ```
 */
export function ProfileCard({
  bapId: bapIdProp,
  address,
  apiUrl,
  className,
  renderAction,
  onExternalLink,
}: ProfileCardProps) {
  const hook = useProfileCard({ bapId: bapIdProp, address, apiUrl })

  return (
    <ProfileCardUI
      className={className}
      bapId={hook.bapId}
      profile={hook.profile}
      currentAddress={hook.currentAddress}
      isLoading={hook.isLoading}
      error={hook.error}
      onRetry={hook.refetch}
      renderAction={renderAction}
      onExternalLink={onExternalLink}
    />
  )
}

"use client"

import { cn } from "@/lib/utils"
import {
  Card,
  CardContent,
  CardHeader,
} from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Separator } from "@/components/ui/separator"
import { Skeleton } from "@/components/ui/skeleton"
import { BitcoinAvatar } from "@/registry/new-york/blocks/bitcoin-avatar"
import { AlertCircle, ExternalLink, RefreshCw } from "lucide-react"
import { Button } from "@/components/ui/button"
import type { BapProfile } from "./use-profile-card"
import type { ReactNode } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ProfileCardUIProps {
  /** Optional CSS class name */
  className?: string
  /** BAP ID (~27 char base58 string) */
  bapId: string | null
  /** Parsed profile data */
  profile: BapProfile | null
  /** Current signing address for avatar resolution */
  currentAddress: string | null
  /** Whether the profile is loading */
  isLoading: boolean
  /** Error from fetching */
  error: Error | null
  /** Retry callback for error state */
  onRetry?: () => void
  /** Render prop for a follow button or other action in the header */
  renderAction?: (bapId: string) => ReactNode
  /** Callback to handle external links (e.g. open in system browser from a WebView) */
  onExternalLink?: (url: string) => void
}

// ---------------------------------------------------------------------------
// Loading skeleton
// ---------------------------------------------------------------------------

function ProfileCardSkeleton({ className }: { className?: string }) {
  return (
    <Card className={cn("w-full max-w-sm", className)}>
      <CardHeader className="flex flex-row items-start gap-4 pb-3">
        <Skeleton className="size-16 shrink-0 rounded-full" />
        <div className="flex-1 flex flex-col gap-2 pt-1">
          <Skeleton className="h-5 w-32" />
          <Skeleton className="h-4 w-24" />
        </div>
      </CardHeader>
      <CardContent className="flex flex-col gap-3">
        <Skeleton className="h-4 w-full" />
        <Skeleton className="h-4 w-3/4" />
        <Separator />
        <Skeleton className="h-4 w-48" />
      </CardContent>
    </Card>
  )
}

// ---------------------------------------------------------------------------
// Error state
// ---------------------------------------------------------------------------

function ProfileCardError({
  className,
  error,
  onRetry,
}: {
  className?: string
  error: Error
  onRetry?: () => void
}) {
  return (
    <Card className={cn("w-full max-w-sm", className)}>
      <CardContent className="flex flex-col items-center gap-3 py-8">
        <div className="flex size-10 items-center justify-center rounded-full bg-destructive/10">
          <AlertCircle className="size-5 text-destructive" />
        </div>
        <p className="text-sm text-muted-foreground text-center">
          {error.message}
        </p>
        {onRetry && (
          <Button variant="outline" size="sm" onClick={onRetry}>
            <RefreshCw data-icon="inline-start" />
            Retry
          </Button>
        )}
      </CardContent>
    </Card>
  )
}

// ---------------------------------------------------------------------------
// Main UI component
// ---------------------------------------------------------------------------

export function ProfileCardUI({
  className,
  bapId,
  profile,
  currentAddress,
  isLoading,
  error,
  onRetry,
  renderAction,
  onExternalLink,
}: ProfileCardUIProps) {
  if (isLoading) {
    return <ProfileCardSkeleton className={className} />
  }

  if (error) {
    return (
      <ProfileCardError
        className={className}
        error={error}
        onRetry={onRetry}
      />
    )
  }

  if (!bapId) {
    return (
      <Card className={cn("w-full max-w-sm", className)}>
        <CardContent className="flex flex-col items-center gap-2 py-8">
          <p className="text-sm text-muted-foreground">
            No identity found
          </p>
        </CardContent>
      </Card>
    )
  }

  const displayName =
    profile?.name ?? profile?.alternateName ?? bapId.slice(0, 8)
  const handle = profile?.alternateName
    ? profile.alternateName.startsWith("@")
      ? profile.alternateName
      : `@${profile.alternateName}`
    : null
  const avatarAddress = currentAddress ?? bapId

  return (
    <Card className={cn("w-full max-w-sm", className)}>
      <CardHeader className="flex flex-row items-start gap-4 pb-3">
        <BitcoinAvatar
          address={avatarAddress}
          imageUrl={profile?.image}
          size="lg"
          className="shrink-0"
        />
        <div className="flex-1 min-w-0 flex flex-col gap-1 pt-0.5">
          <div className="flex items-start justify-between gap-2">
            <div className="min-w-0">
              <p className="text-base font-semibold leading-tight truncate">
                {displayName}
              </p>
              {handle && (
                <p className="text-sm text-muted-foreground truncate">
                  {handle}
                </p>
              )}
            </div>
            {renderAction && bapId ? (
              <div className="shrink-0">{renderAction(bapId)}</div>
            ) : null}
          </div>
        </div>
      </CardHeader>

      <CardContent className="flex flex-col gap-3 pt-0">
        {profile?.description && (
          <p className="text-sm text-muted-foreground leading-relaxed">
            {profile.description}
          </p>
        )}

        <Separator />

        <div className="flex flex-col gap-1.5">
          <p className="text-xs font-medium text-muted-foreground">BAP ID</p>
          <Badge
            variant="secondary"
            className="font-mono text-xs break-all whitespace-normal"
          >
            {bapId}
          </Badge>
        </div>

        {profile?.url && (
          onExternalLink ? (
            <button
              type="button"
              onClick={() => onExternalLink(profile.url as string)}
              className="inline-flex items-center gap-1 text-xs text-primary hover:underline transition-colors"
            >
              {profile.url}
              <ExternalLink className="size-3 flex-shrink-0" />
            </button>
          ) : (
            <a
              href={profile.url}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex items-center gap-1 text-xs text-primary hover:underline transition-colors"
            >
              {profile.url}
              <ExternalLink className="size-3 flex-shrink-0" />
            </a>
          )
        )}
      </CardContent>
    </Card>
  )
}

"use client"

import { useCallback, useEffect, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Schema.org profile fields returned by the 1sat-stack BAP API */
export interface BapProfile {
  /** Display name (givenName + familyName or name) */
  name?: string
  /** Handle / alternate name (e.g. @satoshi) */
  alternateName?: string
  /** Given (first) name */
  givenName?: string
  /** Family (last) name */
  familyName?: string
  /** Short bio / description */
  description?: string
  /** Avatar image URL (may be ord://, b://, or https://) */
  image?: string
  /** Home page or website URL */
  url?: string
}

/** BAP identity record from /1sat/bap/identity/get */
interface BapIdentityRecord {
  idKey: string
  firstSeen: number
  rootAddress: string
  currentAddress: string
  addresses: Array<{ address: string; txId: string; block: number }>
  identity?: Record<string, unknown>
}

/** Response from POST /1sat/bap/identity/validByAddress */
interface BapValidByAddressResponse {
  identity: BapIdentityRecord
  validityRecord: { valid: boolean; block: number }
  profile?: Record<string, unknown>
}

export interface UseProfileCardOptions {
  /** BAP ID to look up directly */
  bapId?: string
  /** Bitcoin address to resolve to a BAP identity */
  address?: string
  /** Base URL for the 1sat-stack API (default: https://api.1sat.app) */
  apiUrl?: string
}

export interface UseProfileCardReturn {
  /** Resolved BAP ID */
  bapId: string | null
  /** Parsed profile data */
  profile: BapProfile | null
  /** Current signing address */
  currentAddress: string | null
  /** Whether profile data is loading */
  isLoading: boolean
  /** Error if fetch failed */
  error: Error | null
  /** Refetch profile data */
  refetch: () => void
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const DEFAULT_API_URL = "https://api.1sat.app"

function parseProfile(raw: Record<string, unknown>): BapProfile {
  return {
    name: typeof raw.name === "string" ? raw.name : undefined,
    alternateName:
      typeof raw.alternateName === "string" ? raw.alternateName : undefined,
    givenName: typeof raw.givenName === "string" ? raw.givenName : undefined,
    familyName: typeof raw.familyName === "string" ? raw.familyName : undefined,
    description:
      typeof raw.description === "string" ? raw.description : undefined,
    image: typeof raw.image === "string" ? raw.image : undefined,
    url: typeof raw.url === "string" ? raw.url : undefined,
  }
}

function buildDisplayName(profile: BapProfile): string | undefined {
  if (profile.name) return profile.name
  if (profile.givenName || profile.familyName) {
    return [profile.givenName, profile.familyName].filter(Boolean).join(" ")
  }
  return undefined
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useProfileCard({
  bapId: bapIdProp,
  address,
  apiUrl = DEFAULT_API_URL,
}: UseProfileCardOptions): UseProfileCardReturn {
  const [bapId, setBapId] = useState<string | null>(bapIdProp ?? null)
  const [profile, setProfile] = useState<BapProfile | null>(null)
  const [currentAddress, setCurrentAddress] = useState<string | null>(null)
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<Error | null>(null)
  const [fetchKey, setFetchKey] = useState(0)

  const refetch = useCallback(() => {
    setFetchKey((k) => k + 1)
  }, [])

  useEffect(() => {
    if (!bapIdProp && !address) return

    let cancelled = false
    setIsLoading(true)
    setError(null)

    async function fetchProfile() {
      try {
        let resolvedBapId = bapIdProp ?? null
        let identityData: BapIdentityRecord | null = null

        // If we have an address but no bapId, resolve via validByAddress
        if (!resolvedBapId && address) {
          const res = await fetch(
            `${apiUrl}/1sat/bap/identity/validByAddress`,
            {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({ address, block: 0 }),
            },
          )
          if (!res.ok) {
            throw new Error(`Failed to resolve address: ${res.status}`)
          }
          const data: BapValidByAddressResponse = await res.json()
          resolvedBapId = data.identity.idKey
          identityData = data.identity
        }

        if (cancelled) return

        // Fetch the identity by bapId if we don't have it yet
        if (resolvedBapId && !identityData) {
          const res = await fetch(`${apiUrl}/1sat/bap/identity/get`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ idKey: resolvedBapId }),
          })
          if (!res.ok) {
            throw new Error(`Failed to fetch identity: ${res.status}`)
          }
          const fetched: BapIdentityRecord = await res.json()
          identityData = fetched
        }

        if (cancelled) return

        // Fetch the profile data
        if (resolvedBapId) {
          const profileRes = await fetch(
            `${apiUrl}/1sat/bap/profile/${encodeURIComponent(resolvedBapId)}`,
          )
          if (profileRes.ok) {
            const profileRaw: Record<string, unknown> =
              await profileRes.json()
            if (cancelled) return
            const parsed = parseProfile(profileRaw)
            // Inject display name if not present
            if (!parsed.name) {
              parsed.name = buildDisplayName(parsed)
            }
            setProfile(parsed)
          }
        }

        if (cancelled) return
        setBapId(resolvedBapId)
        setCurrentAddress(identityData?.currentAddress ?? null)
      } catch (err) {
        if (!cancelled) {
          setError(
            err instanceof Error ? err : new Error("Failed to load profile"),
          )
        }
      } finally {
        if (!cancelled) {
          setIsLoading(false)
        }
      }
    }

    void fetchProfile()

    return () => {
      cancelled = true
    }
  }, [bapIdProp, address, apiUrl, fetchKey])

  return {
    bapId,
    profile,
    currentAddress,
    isLoading,
    error,
    refetch,
  }
}
